// MNIST inference CLI: ./cli_tool weights.json image.png -> prints digit 0-9
#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <cmath>
#include <string>
#include <vector>
#include "lodepng.h"
extern "C" {
#include "cJSON.h"
}

static std::string readFile(const char* path) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", path); exit(1); }
    fseek(f, 0, SEEK_END); long n = ftell(f); fseek(f, 0, SEEK_SET);
    std::string s; s.resize(n);
    if (fread(&s[0], 1, n, f) != (size_t)n) { fclose(f); exit(1); }
    fclose(f);
    return s;
}

// Read a flat vector of doubles from a JSON array (possibly nested), in row-major order.
static void flatten(cJSON* node, std::vector<double>& out) {
    if (cJSON_IsArray(node)) {
        cJSON* c = node->child;
        while (c) { flatten(c, out); c = c->next; }
    } else if (cJSON_IsNumber(node)) {
        out.push_back(node->valuedouble);
    }
}

static std::vector<double> getFlat(cJSON* root, const char* layer, const char* field) {
    cJSON* l = cJSON_GetObjectItemCaseSensitive(root, layer);
    if (!l) { fprintf(stderr, "missing layer %s\n", layer); exit(1); }
    cJSON* fnode = cJSON_GetObjectItemCaseSensitive(l, field);
    if (!fnode) { fprintf(stderr, "missing field %s.%s\n", layer, field); exit(1); }
    std::vector<double> v;
    flatten(fnode, v);
    return v;
}

// y = ReLU?(W x + b); W is [out][in] row-major, x length in.
static std::vector<double> linear(const std::vector<double>& W, const std::vector<double>& b,
                                  const std::vector<double>& x, int out, int in, bool relu) {
    std::vector<double> y(out);
    for (int o = 0; o < out; o++) {
        double s = b[o];
        const double* wr = &W[(size_t)o * in];
        for (int i = 0; i < in; i++) s += wr[i] * x[i];
        if (relu && s < 0) s = 0;
        y[o] = s;
    }
    return y;
}

int main(int argc, char** argv) {
    if (argc < 3) { fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]); return 1; }

    // Load weights
    std::string js = readFile(argv[1]);
    cJSON* root = cJSON_Parse(js.c_str());
    if (!root) { fprintf(stderr, "invalid json\n"); return 1; }

    std::vector<double> Wi = getFlat(root, "input_layer", "weight");
    std::vector<double> bi = getFlat(root, "input_layer", "bias");
    std::vector<double> Wh = getFlat(root, "hidden_layer", "weight");
    std::vector<double> bh = getFlat(root, "hidden_layer", "bias");
    std::vector<double> Wo = getFlat(root, "output_layer", "weight");
    std::vector<double> bo = getFlat(root, "output_layer", "bias");

    int hidden = (int)bi.size();
    int classes = (int)bo.size();
    int input = (int)(Wi.size() / (hidden ? hidden : 1));

    // Load and decode image (grayscale)
    std::vector<unsigned char> png;
    if (lodepng::load_file(png, argv[2])) { fprintf(stderr, "cannot read image\n"); return 1; }
    std::vector<unsigned char> gray;
    unsigned w = 0, h = 0;
    unsigned err = lodepng::decode(gray, w, h, png, LCT_GREY, 8);
    if (err) { fprintf(stderr, "png decode error: %s\n", lodepng_error_text(err)); return 1; }

    if ((int)(w * h) != input) {
        fprintf(stderr, "image size %ux%u != input %d\n", w, h, input);
        return 1;
    }

    // Preprocess: ToTensor -> [0,1], Normalize(mean=0.1307, std=0.3081)
    const double mean = 0.1307, sd = 0.3081;
    std::vector<double> x(input);
    for (int i = 0; i < input; i++) x[i] = ((gray[i] / 255.0) - mean) / sd;

    std::vector<double> h1 = linear(Wi, bi, x,  hidden, input,  true);
    std::vector<double> h2 = linear(Wh, bh, h1, hidden, hidden, true);
    std::vector<double> o  = linear(Wo, bo, h2, classes, hidden, false);

    int best = 0;
    for (int i = 1; i < classes; i++) if (o[i] > o[best]) best = i;

    printf("%d\n", best);
    cJSON_Delete(root);
    return 0;
}

